parameters.systemDirective:
=Convert the user's tool request into STRICT JSON matching exactly this schema:
{
  "action": "write_file" | "read_file" | "list_directory",
  "path": "THE ABSOLUTE PATH OR FILENAME",
  "content": "THE DATA TO WRITE (if write_file)"
}
Respond ONLY with raw JSON. No markdown backticks. No explanation.

CONTEXT:
{{ $node["Get Short-Term"].json.map(m => m.sender + ": " + m.content).reverse().join("\n") }}

parameters.jsCode:
const response = $input.item.json.response || '';
let jsonMatch = response.match(/\{[\s\S]*\}/);
let parsed = { action: 'error', message: 'No valid JSON found', content: '' };

if (jsonMatch) {
  try {
    parsed = JSON.parse(jsonMatch[0]);
    if (parsed.content === undefined) parsed.content = '';
    if (parsed.path) {
      // Normalize path
      let normalizedPath = parsed.path.replace(/\\/g, '/');
      if (normalizedPath.toLowerCase().startsWith('c:/axiom_files')) {
          parsed.isExternal = false;
          parsed.fullPath = normalizedPath;
      } else {
          parsed.isExternal = true;
          parsed.fullPath = normalizedPath;
      }
    }
  } catch(e) {
    parsed = { action: 'error', message: 'Malformed JSON response: ' + e.message, content: '' };
  }
}
return { json: parsed };

